import numpy as np
from typing import List, Dict
from dataclasses import dataclass

@dataclass
class JobProfile:
    job_id: str
    phases: Dict[str, float]

class JobStatistics:
    """Analyze statistics across multiple jobs."""

    def __init__(self):
        self.profiles: List[JobProfile] = []

    def add_profile(self, profile: JobProfile):
        """Add a job profile."""
        self.profiles.append(profile)

    def get_phase_stats(self, phase: str) -> Dict:
        """Get statistics for a specific phase."""
        times = [p.phases.get(phase, 0) for p in self.profiles if phase in p.phases]
        if not times:
            return {}

        return {
            'mean': np.mean(times),
            'std': np.std(times),
            'min': np.min(times),
            'max': np.max(times),
            'median': np.median(times),
            'count': len(times)
        }

    def get_all_stats(self) -> Dict[str, Dict]:
        """Get statistics for all phases."""
        all_phases = set()
        for p in self.profiles:
            all_phases.update(p.phases.keys())

        return {phase: self.get_phase_stats(phase) for phase in all_phases}

    def find_outliers(self, phase: str, threshold: float = 2.0) -> List[str]:
        """Find jobs with outlier timing."""
        stats = self.get_phase_stats(phase)
        if not stats:
            return []

        mean, std = stats['mean'], stats['std']
        outliers = []

        for p in self.profiles:
            if phase in p.phases:
                if abs(p.phases[phase] - mean) > threshold * std:
                    outliers.append(p.job_id)

        return outliers

    def print_summary(self):
        """Print statistical summary."""
        print("\nJob Statistics Summary")
        print("=" * 70)
        print(f"Total Jobs: {len(self.profiles)}")
        print("\nPhase Statistics:")
        print(f"{'Phase':<15} {'Mean':<10} {'Std':<10} {'Min':<10} {'Max':<10}")
        print("-" * 70)

        for phase, stats in self.get_all_stats().items():
            print(f"{phase:<15} {stats['mean']:<10.2f} {stats['std']:<10.2f} "
                  f"{stats['min']:<10.2f} {stats['max']:<10.2f}")

# Test
np.random.seed(42)
stats = JobStatistics()
for i in range(20):
    stats.add_profile(JobProfile(
        job_id=f"job_{i}",
        phases={
            'transpile': np.random.normal(50, 10),
            'execute': np.random.normal(100, 20),
            'process': np.random.normal(5, 1)
        }
    ))

stats.print_summary()
print(f"\nOutliers in execute: {stats.find_outliers('execute')}")

import time
import json
from functools import wraps
from typing import Callable, Dict, List
from datetime import datetime

class AutoProfiler:
    """Automated profiling system."""

    def __init__(self, alert_threshold_ms: float = 1000):
        self.alert_threshold = alert_threshold_ms
        self.profiles: List[Dict] = []
        self.alerts: List[str] = []

    def profile(self, name: str = None):
        """Decorator to automatically profile functions."""
        def decorator(func: Callable):
            func_name = name or func.__name__

            @wraps(func)
            def wrapper(*args, **kwargs):
                start = time.perf_counter()
                try:
                    result = func(*args, **kwargs)
                    status = "success"
                except Exception as e:
                    result = None
                    status = f"error: {str(e)}"
                finally:
                    duration_ms = (time.perf_counter() - start) * 1000

                # Record profile
                profile = {
                    'name': func_name,
                    'duration_ms': duration_ms,
                    'status': status,
                    'timestamp': datetime.now().isoformat()
                }
                self.profiles.append(profile)

                # Check for alerts
                if duration_ms > self.alert_threshold:
                    alert = f"SLOW: {func_name} took {duration_ms:.2f}ms (threshold: {self.alert_threshold}ms)"
                    self.alerts.append(alert)

                return result
            return wrapper
        return decorator

    def export_json(self, filepath: str):
        """Export profiles to JSON."""
        with open(filepath, 'w') as f:
            json.dump({
                'profiles': self.profiles,
                'alerts': self.alerts,
                'summary': self._get_summary()
            }, f, indent=2)

    def _get_summary(self) -> Dict:
        """Get summary statistics."""
        if not self.profiles:
            return {}

        by_name = {}
        for p in self.profiles:
            name = p['name']
            if name not in by_name:
                by_name[name] = []
            by_name[name].append(p['duration_ms'])

        return {
            name: {
                'count': len(times),
                'mean_ms': sum(times) / len(times),
                'max_ms': max(times)
            }
            for name, times in by_name.items()
        }

    def generate_report(self) -> str:
        """Generate text report."""
        lines = ["\n" + "=" * 50, "AUTO PROFILER REPORT", "=" * 50]
        lines.append(f"Total functions profiled: {len(self.profiles)}")
        lines.append(f"Alerts triggered: {len(self.alerts)}")

        lines.append("\nFunction Statistics:")
        lines.append("-" * 50)

        summary = self._get_summary()
        for name, stats in summary.items():
            lines.append(f"  {name}: {stats['count']} calls, "
                        f"mean={stats['mean_ms']:.2f}ms, max={stats['max_ms']:.2f}ms")

        if self.alerts:
            lines.append("\nAlerts:")
            for alert in self.alerts:
                lines.append(f"  ⚠️ {alert}")

        return "\n".join(lines)

    def get_alerts(self) -> List[str]:
        """Get triggered alerts."""
        return self.alerts

# Test
profiler = AutoProfiler(alert_threshold_ms=50)

@profiler.profile("fast_function")
def fast_func():
    time.sleep(0.01)
    return "done"

@profiler.profile("slow_function")
def slow_func():
    time.sleep(0.1)
    return "done"

fast_func()
slow_func()
fast_func()

print(profiler.generate_report())
print(f"\nAlerts: {profiler.get_alerts()}")
